/* ───────────────────────────────────────────
   CAROUSEL
─────────────────────────────────────────── */
const slides = document.querySelectorAll('.carousel-slide');
const dotsContainer = document.getElementById('carousel-dots');
let currentSlide = 0;
let carouselTimer = null;

// Build dots
slides.forEach((_, i) => {
  const dot = document.createElement('button');
  dot.className = 'carousel-dot' + (i === 0 ? ' active' : '');
  dot.setAttribute('aria-label', 'Go to slide ' + (i + 1));
  dot.addEventListener('click', () => goToSlide(i));
  dotsContainer.appendChild(dot);
});

function goToSlide(index) {
  slides[currentSlide].classList.remove('active');
  dotsContainer.children[currentSlide].classList.remove('active');
  currentSlide = (index + slides.length) % slides.length;
  slides[currentSlide].classList.add('active');
  dotsContainer.children[currentSlide].classList.add('active');
  resetCarouselTimer();
}

function moveCarousel(direction) {
  goToSlide(currentSlide + direction);
}

function resetCarouselTimer() {
  clearInterval(carouselTimer);
  carouselTimer = setInterval(() => goToSlide(currentSlide + 1), 4000);
}

resetCarouselTimer();

/* ───────────────────────────────────────────
   AUDIO PLAYER
─────────────────────────────────────────── */
const audio = document.getElementById('my-audio');
const playBtn = document.getElementById('play-btn');
const progressBar = document.getElementById('progress-bar');
const audioTime = document.getElementById('audio-time');

function togglePlay() {
  if (audio.paused) {
    audio.play();
    playBtn.innerHTML = '&#9646;&#9646;';
    bgMusic.volume = 0.1; // lower bg music while voice plays
  } else {
    audio.pause();
    playBtn.innerHTML = '&#9654;';
    bgMusic.volume = 0.8; // restore bg music
  }
}

function formatTime(secs) {
  const m = Math.floor(secs / 60);
  const s = Math.floor(secs % 60);
  return m + ':' + (s < 10 ? '0' : '') + s;
}

audio.addEventListener('timeupdate', () => {
  if (audio.duration) {
    const pct = (audio.currentTime / audio.duration) * 100;
    progressBar.style.width = pct + '%';
    audioTime.textContent = formatTime(audio.currentTime);
  }
});

audio.addEventListener('ended', () => {
  playBtn.innerHTML = '&#9654;';
  progressBar.style.width = '0%';
  audioTime.textContent = '0:00';
  bgMusic.volume = 0.8; // restore bg music when voice message finishes
});

function seekAudio(e) {
  const wrap = e.currentTarget;
  const rect = wrap.getBoundingClientRect();
  const pct = (e.clientX - rect.left) / rect.width;
  if (audio.duration) {
    audio.currentTime = pct * audio.duration;
  }
}

/* ───────────────────────────────────────────
   STUDENT PAGE
─────────────────────────────────────────── */
function goToStudentPage() {
  const select = document.getElementById('student-select');
  const key = select.value;
  const errorMsg = document.getElementById('error-msg');

  if (!key || !students[key]) {
    errorMsg.style.display = 'block';
    return;
  }
  errorMsg.style.display = 'none';

  const student = students[key];
  const initials = student.name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();

  document.getElementById('student-avatar').textContent = initials;
  document.getElementById('student-name').textContent = student.name;
  const formatted = ('\u201c' + student.message + '\u201d')
  .replace(/\n/g, '<br>');
  document.getElementById('student-message').innerHTML = formatted;  document.getElementById('teacher-name').textContent = TEACHER_NAME;

  const homePage = document.getElementById('home-page');
  const studentPage = document.getElementById('student-page');

  homePage.style.opacity = '0';
  homePage.style.transition = 'opacity 0.25s ease';

  setTimeout(() => {
    homePage.style.display = 'none';
    homePage.style.opacity = '';
    homePage.style.transition = '';
    studentPage.style.display = 'flex';
    studentPage.classList.remove('page-fade-in');
    void studentPage.offsetWidth;
    studentPage.classList.add('page-fade-in');
    window.scrollTo({ top: 0, behavior: 'smooth' });
    launchConfetti(); // ← moved in here
  }, 250);

  window.scrollTo({ top: 0, behavior: 'smooth' });
  launchConfetti();
}

function goBack() {
  const homePage = document.getElementById('home-page');
  const studentPage = document.getElementById('student-page');

  studentPage.style.opacity = '0';
  studentPage.style.transition = 'opacity 0.25s ease';

  setTimeout(() => {
    studentPage.style.display = 'none';
    studentPage.style.opacity = '';
    studentPage.style.transition = '';
    document.getElementById('student-select').value = '';
    homePage.style.display = 'flex';
    homePage.classList.remove('page-fade-in');
    void homePage.offsetWidth;
    homePage.classList.add('page-fade-in');
  }, 250);
}

/* ───────────────────────────────────────────
   CONFETTI
─────────────────────────────────────────── */
const canvas = document.getElementById('confetti-canvas');
const ctx = canvas.getContext('2d');

canvas.width = window.innerWidth;
canvas.height = window.innerHeight;
window.addEventListener('resize', () => {
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
});

const COLORS = ['#c19a6b', '#e8c99a', '#f0d9b5', '#3b2f1e', '#a0522d', '#f4c97a', '#fff8ee'];
let confettiPieces = [];
let animationId = null;

function randomBetween(a, b) { return a + Math.random() * (b - a); }

function createPiece() {
  return {
    x: randomBetween(0, canvas.width),
    y: randomBetween(-200, 50),
    w: randomBetween(8, 16),
    h: randomBetween(6, 12),
    color: COLORS[Math.floor(Math.random() * COLORS.length)],
    rotation: randomBetween(0, Math.PI * 2),
    rotSpeed: randomBetween(-0.08, 0.08),
    vx: randomBetween(-2, 2),
    vy: randomBetween(3, 7),
    opacity: 1
  };
}

function launchConfetti() {
  if (animationId) cancelAnimationFrame(animationId);
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  confettiPieces = Array.from({ length: 160 }, createPiece);
  animateConfetti();
}

function animateConfetti() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  confettiPieces.forEach(p => {
    p.x += p.vx;
    p.y += p.vy;
    p.vy += 0.08;
    p.rotation += p.rotSpeed;
    if (p.y > canvas.height * 0.75) p.opacity -= 0.025;
    ctx.save();
    ctx.globalAlpha = Math.max(0, p.opacity);
    ctx.translate(p.x, p.y);
    ctx.rotate(p.rotation);
    ctx.fillStyle = p.color;
    ctx.fillRect(-p.w / 2, -p.h / 2, p.w, p.h);
    ctx.restore();
  });
  confettiPieces = confettiPieces.filter(p => p.opacity > 0 && p.y < canvas.height + 20);
  if (confettiPieces.length > 0) {
    animationId = requestAnimationFrame(animateConfetti);
  } else {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    animationId = null;
  }
}

